import pytest
from datetime import date, timedelta

def test_create_savings_goal_unauthenticated_returns_401(api_client):
    payload = {
        "name": "Unauth Goal",
        "target_amount": 200.00,
        "target_date": str(date.today() + timedelta(days=60)),
    }
    resp = api_client.post("/goals", json=payload)
    assert resp.status_code == 401
